import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Empty / trivial cases ---
  it.todo("empty item list → premium 5 G (only the processing fee)");

  // --- Base premiums for main items (single item, no modifiers, 1st-time customer with no prior contract) ---
  // For these isolated base-premium tests we expect: base + 10% first insurance + 5 fee, rounded up in MHPCO's favor.
  it.todo("quote for a single plain sword (steel, enchantment 3) → 100 G base premium drives the calculation");
  it.todo("quote for a single plain amulet → 60 G base premium drives the calculation");
  it.todo("quote for a single plain staff → 80 G base premium drives the calculation");
  it.todo("quote for a single plain potion → 40 G base premium drives the calculation");

  // --- Component base premiums and blocks of 3 alike ---
  it.todo("2 runes → 50 G base premium (no block)");
  it.todo("3 runes → 60 G base premium (block applies)");
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium (no blocks formed; spec example)");
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // --- Premium modifiers in isolation (newcomer scenarios anchor expected totals) ---
  it.todo("newcomer with a cursed sword (steel, enchantment 3) → premium 165 G (integration example)");
  it.todo("sword with enchantment 4 (not cursed) → no high-enchantment surcharge");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("cursed sword with exactly enchantment 5 → both surcharges apply");

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword + plain amulet → base 160 G, +50 G curse surcharge on the sword only → 210 G before policy modifiers and fee");

  // --- Loyalty / first insurance / follow-up modifiers ---
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("long-standing customer's second contract: cursed sword enchantment 7 → premium 160 G (integration example; first insurance surcharge still applies per item)");

  // --- Rounding in MHPCO's favor ---
  it.todo("a premium calculation that yields 197.5 G → final premium 198 G (rounded up)");
  it.todo("a payout calculation that yields 350.5 G → final payout 350 G (rounded down)");

  // --- Claim processing: deductibles and standard reimbursement ---
  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (full reimbursement minus 100 G deductible)");
  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (full reimbursement minus 100 G deductible)");
  it.todo("dragon attack damages an insured sword (500 G) and amulet (300 G) → payout 600 G (100 G deductible per damaged item)");

  // --- Claim processing: special clauses ---
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50 % rule wins, then deductible)");
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (only dragon-material clause applies)");
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (only high-enchantment clause applies)");
  it.todo("dragon-material sword with exactly enchantment 8, damage 1000 G → payout 400 G (high-enchantment clause applies first, then deductible)");

  // --- Multiple items of same type and cap exhaustion ---
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G; dragon attack damages both → each entry treated as separate damage with its own deductible");
  it.todo("policy covers a sword and an amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (insurance value 1000 G) → cap 2000 G (based on unmodified insurance value)");
  it.todo("policy covers a sword and 3 runes (block) → insurance sum 1750 G (block discount affects premium only, not insurance sum)");
  it.todo("sword insured (cap 2000 G); first claim 1500 G → payout 1400 G, remainingCap 600 G");
  it.todo("sword insured (cap 2000 G); after first 1500 G claim, second claim 1500 G → payout 600 G, remainingCap 0 G");

  // --- Error/edge cases ---
  it.todo("quote includes an item with an unknown type → throws an error (CLI exits non-zero)");
  it.todo("claim references a damage entry whose item is not part of the policy → throws an error");
  it.todo("claim has more damage entries of a given type than the policy covers → throws an error");
  it.todo("claim contains a damage entry with amount: -200 → throws an error");
});

