const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Array<Item> };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<QuoteStep>;
};

const quoteStep = (step: QuoteStep): { premium: number } => {
  if (step.items.length === 0) {
    return { premium: PROCESSING_FEE };
  }
  const basePremium = step.items.reduce(
    (sum, item) => sum + BASE_PREMIUM[item.type],
    0,
  );
  const premium = basePremium * (1 + FIRST_INSURANCE_SURCHARGE) + PROCESSING_FEE;
  return { premium: Math.ceil(premium) };
};

export const processScenario = (scenario: unknown): unknown => {
  const { steps } = scenario as Scenario;
  return { results: steps.map(quoteStep) };
};

