const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const FLOAT_ROUNDING_TOLERANCE = 1e-9;
const BLOCK_OF_THREE_DISCOUNT = 15;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = { type: string; cursed?: boolean };
type QuoteStep = { op: "quote"; items: Array<Item> };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<QuoteStep>;
};

const roundUpInMHPCOFavor = (amount: number): number =>
  Math.ceil(amount - FLOAT_ROUNDING_TOLERANCE);

const CURSE_SURCHARGE = 0.5;

const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];

const curseSurchargeFor = (item: Item): number =>
  item.cursed ? basePremiumOf(item) * CURSE_SURCHARGE : 0;

const sumOfBasePrices = (items: Array<Item>): number =>
  items.reduce((sum, item) => sum + basePremiumOf(item), 0);

const sumOfItemSurcharges = (items: Array<Item>): number =>
  items.reduce((sum, item) => sum + curseSurchargeFor(item), 0);

const COMPONENT_TYPES = ["rune", "moonstone"];
const BLOCK_SIZE = 3;

const countOfType = (items: Array<Item>, type: string): number =>
  items.filter((item) => item.type === type).length;

const formsABlock = (items: Array<Item>, type: string): boolean =>
  countOfType(items, type) === BLOCK_SIZE;

const blockDiscountFor = (items: Array<Item>): number =>
  COMPONENT_TYPES.filter((type) => formsABlock(items, type)).length *
  BLOCK_OF_THREE_DISCOUNT;

const basePremiumFor = (items: Array<Item>): number =>
  sumOfBasePrices(items) - blockDiscountFor(items);

const withFirstInsuranceSurcharge = (amount: number): number =>
  amount * (1 + FIRST_INSURANCE_SURCHARGE);

const withProcessingFee = (amount: number): number => amount + PROCESSING_FEE;

const quoteStep = (step: QuoteStep): { premium: number } => {
  const basePremium = basePremiumFor(step.items);
  const itemSurchargeTotal = sumOfItemSurcharges(step.items);
  const premiumBeforeRounding = withProcessingFee(
    withFirstInsuranceSurcharge(basePremium) + itemSurchargeTotal,
  );
  return { premium: roundUpInMHPCOFavor(premiumBeforeRounding) };
};

export const processScenario = (scenario: unknown): unknown => {
  const { steps } = scenario as Scenario;
  return { results: steps.map(quoteStep) };
};

