65	  { applies: (item) => item.cursed === true, rate: 0.5 },
66	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD, rate: 0.3 },
67	];
68	
69	const surchargesFor = (item: Item): number =>
70	  ITEM_SURCHARGES.reduce(
71	    (sum, { applies, rate }) => sum + (applies(item) ? basePremiumOf(item) * rate : 0),
72	    0,
73	  );
74	
75	const sumOfBasePrices = (items: Array<Item>): number =>
76	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
77	
78	const sumOfItemSurcharges = (items: Array<Item>): number =>
79	  items.reduce((sum, item) => sum + surchargesFor(item), 0);
80	
81	const COMPONENT_TYPES = ["rune", "moonstone"];
82	const BLOCK_SIZE = 3;
83	
84	const countsByKey = <T>(xs: Array<T>, keyOf: (x: T) => string): Map<string, number> =>
85	  xs.reduce(
86	    (counts, x) => counts.set(keyOf(x), (counts.get(keyOf(x)) ?? 0) + 1),
87	    new Map<string, number>(),
88	  );
89	
90	const countOfType = (items: Array<Item>, type: string): number =>
91	  items.filter((item) => item.type === type).length;
92	
93	const formsABlock = (items: Array<Item>, type: string): boolean =>
94	  countOfType(items, type) === BLOCK_SIZE;
95	
96	const blockDiscountFor = (items: Array<Item>): number =>
97	  COMPONENT_TYPES.filter((type) => formsABlock(items, type)).length *
98	  BLOCK_OF_THREE_DISCOUNT;
99	
100	const basePremiumFor = (items: Array<Item>): number =>
101	  sumOfBasePrices(items) - blockDiscountFor(items);
102	
103	type PolicyContext = { customer: Customer; isFollowUp: boolean };
104	type PolicyAdjustment = { applies: (ctx: PolicyContext) => boolean; signedRate: number };
105	
106	const POLICY_ADJUSTMENTS: Array<PolicyAdjustment> = [
107	  { applies: () => true, signedRate: +FIRST_INSURANCE_SURCHARGE },
108	  { applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, signedRate: -LOYALTY_DISCOUNT },
109	  { applies: ({ isFollowUp }) => isFollowUp, signedRate: -FOLLOW_UP_CONTRACT_DISCOUNT },
110	];
111	
112	const policyAdjustmentsOn = (policyBase: number, ctx: PolicyContext): number =>
113	  POLICY_ADJUSTMENTS.reduce(
114	    (sum, { applies, signedRate }) => sum + (applies(ctx) ? policyBase * signedRate : 0),
115	    0,
116	  );
117	
118	const quoteStep = (step: QuoteStep, ctx: PolicyContext): { premium: number } => {
119	  const policyBase = basePremiumFor(step.items);
120	  const premiumBeforeRounding =
121	    policyBase
122	    + policyAdjustmentsOn(policyBase, ctx)
123	    + sumOfItemSurcharges(step.items)
124	    + PROCESSING_FEE;
125	  return { premium: roundUpInMHPCOFavor(premiumBeforeRounding) };
126	};
127	
128	const DEDUCTIBLE = 100;
129	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
130	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
131	
132	const findInsuredItem = (policy: QuoteStep, itemType: string): Item =>
133	  requireDefined(
134	    policy.items.find((item) => item.type === itemType),
135	    `Item not in policy: ${itemType}`,
136	  );
137	
138	const reimbursementOf = (item: Item, damage: Damage): number =>
139	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
140	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
141	    : damage.amount;
142	
143	const payoutForDamage = (item: Item, damage: Damage): number =>
144	  reimbursementOf(item, damage) - DEDUCTIBLE;
145	
146	const sumOfInsuranceValues = (items: Array<Item>): number =>
147	  items.reduce((sum, item) => sum + insuranceValueOf(item), 0);
148	
149	const capFor = (policy: QuoteStep): number =>
150	  CAP_MULTIPLIER * sumOfInsuranceValues(policy.items);
151	
152	const assertDamageAmountsNonNegative = (step: ClaimStep): void => {
153	  const negative = step.incident.damages.find((damage) => damage.amount < 0);
154	  if (negative !== undefined) {
155	    throw new Error(`Damage amount must be non-negative: ${negative.amount}`);
156	  }
157	};
158	
159	const assertDamagesFitPolicy = (step: ClaimStep, policy: QuoteStep): void => {
160	  const insuredCounts = countsByKey(policy.items, (item) => item.type);
161	  const damageCounts = countsByKey(step.incident.damages, (damage) => damage.itemType);
162	  for (const [itemType, dmgCount] of damageCounts) {
163	    if (dmgCount > (insuredCounts.get(itemType) ?? 0)) {
164	      throw new Error(`Damage entries exceed insured count for: ${itemType}`);
165	    }
166	  }
167	};
168	
169	const assertClaimIsValid = (step: ClaimStep, policy: QuoteStep): void => {
170	  assertDamageAmountsNonNegative(step);
171	  assertDamagesFitPolicy(step, policy);
172	};
173	
174	const claimStep = (
175	  step: ClaimStep,
176	  policy: QuoteStep,
177	  remainingCap: number,
178	): { payout: number; remainingCap: number } => {
179	  assertClaimIsValid(step, policy);
180	  const payoutBeforeRounding = step.incident.damages.reduce(
181	    (sum, damage) => sum + payoutForDamage(findInsuredItem(policy, damage.itemType), damage),
182	    0,
183	  );
184	  const desiredPayout = roundDownInMHPCOFavor(payoutBeforeRounding);
185	  const payout = Math.min(desiredPayout, remainingCap);
186	  return { payout, remainingCap: remainingCap - payout };
187	};
188	
189	const isQuoteStep = (step: Step): step is QuoteStep => step.op === "quote";
190	
191	const claimAgainstRemainingCap = (
192	  step: ClaimStep,
193	  steps: Array<Step>,
194	  remainingCapByPolicy: Map<number, number>,
195	): { payout: number; remainingCap: number } => {
196	  const policy = steps[step.policy] as QuoteStep;
197	  const currentCap = remainingCapByPolicy.get(step.policy) ?? capFor(policy);
198	  const result = claimStep(step, policy, currentCap);
199	  remainingCapByPolicy.set(step.policy, result.remainingCap);
200	  return result;
201	};
202	
203	export const processScenario = (scenario: unknown): unknown => {
204	  const { customer, steps } = scenario as Scenario;
205	  const remainingCapByPolicy = new Map<number, number>();
206	  const results = steps.map((step, index) =>
207	    isQuoteStep(step)
208	      ? quoteStep(step, { customer, isFollowUp: index > 0 })
209	      : claimAgainstRemainingCap(step, steps, remainingCapByPolicy),
210	  );
211	  return { results };
212	};

